  for (let i = 0; i < vertices.length - 1; i++) {
    for (const { from, to, weight } of edges) {
      if (dist[from] !== Infinity &&
          dist[from] + weight < dist[to]) {
        dist[to] = dist[from] + weight;
      }
    }
  }

  // Check for negative-weight cycles
