  const dist = graph.map(row => [...row]);

  // Set diagonal to 0
  for (let i = 0; i < V; i++) dist[i][i] = 0;

  // Try every vertex k as intermediate point
  for (let k = 0; k < V; k++) {
    for (let i = 0; i < V; i++) {
      for (let j = 0; j < V; j++) {
        if (dist[i][k] + dist[k][j] < dist[i][j]) {
          dist[i][j] = dist[i][k] + dist[k][j];
        }
      }
    }
  }
  // dist[i][j] now holds shortest path from i to j
  return dist;
